module RefModule (
    input clk,
    input rst,
    input en,
    input d,
    output reg q
);
  wire _tap_clk = clk & {1{1'b1}};


    always @(posedge clk or posedge rst) begin
        if (rst) begin
            q <= 1'b0;
        end else if (en) begin
            q <= d;
        end
    end

endmodule
